definition.script:
def Branch = "dev"
def Project_User = "dainguyenx3"
def Project_Repository = "https://git.x3english.com/scm/set/suzu-api.git"
def Username = "jenkins"
def IP_Server = ["13.250.62.89"]
def Web_Folder = "/var/www/html"
def Project_Folder = "suzu.goga.ai"
def text_body_email = "Hi guys, \nYour project ${JOB_NAME} has been ${currentBuild.currentResult}. \nCheck console output at ${BUILD_URL} to view the results. \nThanks you. \n--------------------------------------------------- \nPhạm Tiến Minh Đức - DevOps Engineer \nEmail: ducpham@x3english.com \nX3English -  Tầng 1, Tháp B Tòa Nhà The Light, Tố Hữu, Trung Văn, Nam Từ Liêm, Hà Nội 100000 "
def title_email = "[Jenkins] Jenkins's report for ${JOB_NAME} - Build # ${BUILD_NUMBER}"
def receiver = 'ducpham@x3english.com'
node('master') {
            stage("Pull code from GitLab"){
                echo "This will be deployed to server Test"
                git branch: "${Branch}", credentialsId: "${Project_User}", url: "${Project_Repository}"
            }
            stage("Prepare for deploying"){              
            }
            stage("Clear old test file"){
               for (i=0 ; i<IP_Server.size() ; i++){
                    sh """
                    ssh $Username@${IP_Server[i]} "cd $Web_Folder/$Project_Folder && rm -rf test/*"
                    """
                }
            }    
            stage("Push code to staging server"){
               for (i=0 ; i<IP_Server.size() ; i++){
                    sh """
                    /usr/bin/rsync -azrv '--exclude=.gitignore' '--exclude=.git' '--exclude=.env' $WORKSPACE/ $Username@${IP_Server[i]}:$Web_Folder/$Project_Folder
                    """
                }
            }
            stage("Install package"){
               for (i=0 ; i<IP_Server.size() ; i++){
                    sh """
                    ssh $Username@${IP_Server[i]} "cd $Web_Folder/$Project_Folder && yarn"
                    """
                }
            }
            stage("Run Test"){
               for (i=0 ; i<IP_Server.size() ; i++){
                    sh """
                    ssh $Username@${IP_Server[i]} "cd $Web_Folder/$Project_Folder && npm run test"
                    """
                }
            }
            stage("PM2 Reload"){
               for (i=0 ; i<IP_Server.size() ; i++){
                    sh """
                    ssh $Username@${IP_Server[i]} "pm2 reload $Web_Folder/$Project_Folder/ecosystem.config.js"
                    """
                }
            }
}
emailext body: "${text_body_email}", subject: "${title_email}", to: "${receiver}"
slackSend(channel: "#general", message: "${text_body_email}")
